      series: [ {x:"2007.1",v:1418}, {x:"2007.10",v:1565}, {x:"2007.12",v:1468}, {x:"2008.3",v:1323}, {x:"2008.5",v:1400}, {x:"2008.7",v:1267}, {x:"2008.9",v:1166}, {x:"2008.10",v:969}, {x:"2008.11",v:896}, {x:"2009.1",v:826}, {x:"2009.3",v:677}, {x:"2009.6",v:919}, {x:"2009.12",v:1115}, {x:"2010.4",v:1217}, {x:"2010.8",v:1049}, {x:"2011.4",v:1331}, {x:"2011.9",v:1131}, {x:"2012.3",v:1408}, {x:"2012.12",v:1426}, {x:"2013.4",v:1569} ],
